static void do_mem_peek(const struct cli_cmd_entry *pEntry)
{
    uint32_t addr;
    (void)pEntry;
    CLI_uint32_required("addr", &addr);
    CLI_printf("value 0x%08x\n", *(volatile uint32_t *)addr);
}

static void do_mem_poke(const struct cli_cmd_entry *pEntry)
{
    uint32_t addr;
    uint32_t value;
    (void)pEntry;
    CLI_uint32_required("addr", &addr);
    CLI_uint32_required("value", &value);
    *(volatile uint32_t *)addr = value;
    CLI_printf("<<DONE>>\n");
}

