/* ── io ─────────────────────────────────────────────────────────────────── */

static void do_io_setmux(const struct cli_cmd_entry *pEntry)
{
    uint32_t io_pad;
    uint32_t mux;
    uint8_t readback;
    (void)pEntry;
    CLI_uint32_required("io_pad", &io_pad);
    CLI_uint32_required("mux_sel", &mux);
    gpio_setpinmux((uint8_t)io_pad, (uint8_t)mux);
    readback = gpio_getpinmux((uint8_t)io_pad);
    if (readback == (uint8_t)mux)
    {
        CLI_printf("io setmux %d <<PASSED>>\n", io_pad);
    }
    else
    {
        CLI_printf("io setmux %d <<FAILED>> (readback=0x%x)\n", io_pad, readback);
    }
}

static void do_io_getmux(const struct cli_cmd_entry *pEntry)
{
    uint32_t io_pad;
    (void)pEntry;
    CLI_uint32_required("io_pad", &io_pad);
    CLI_printf("mux_sel 0x%x\n", gpio_getpinmux((uint8_t)io_pad));
}

static const struct cli_cmd_entry io_menu[] = {
    CLI_CMD_SIMPLE("setmux", do_io_setmux, "io_pad mux_sel -- set pad mux function"),
    CLI_CMD_SIMPLE("getmux", do_io_getmux, "io_pad -- read pad mux function"),
    CLI_CMD_TERMINATE()
};

/* ── gpio ───────────────────────────────────────────────────────────────── */

static void do_gpio_set(const struct cli_cmd_entry *pEntry)
{
    uint32_t pin;
    (void)pEntry;
    CLI_uint32_required("gpio_num", &pin);
    gpio_set(1UL << pin);
    CLI_printf("<<DONE>>\n");
}

static void do_gpio_clr(const struct cli_cmd_entry *pEntry)
{
    uint32_t pin;
    (void)pEntry;
    CLI_uint32_required("gpio_num", &pin);
    gpio_clear(1UL << pin);
    CLI_printf("<<DONE>>\n");
}

static void do_gpio_toggle(const struct cli_cmd_entry *pEntry)
{
    uint32_t pin;
    (void)pEntry;
    CLI_uint32_required("gpio_num", &pin);
    gpio_toggle(1UL << pin);
    CLI_printf("<<DONE>>\n");
}

static void do_gpio_mode(const struct cli_cmd_entry *pEntry)
{
    uint32_t pin;
    uint32_t mode;
    (void)pEntry;
    CLI_uint32_required("gpio_num", &pin);
    CLI_uint32_required("gpio_mode", &mode);
    gpio_pin_set_dir((uint8_t)pin, (uint8_t)mode);
    CLI_printf("<<DONE>>\n");
}

static void do_gpio_status(const struct cli_cmd_entry *pEntry)
{
    uint32_t pin;
    uint32_t stat;
    (void)pEntry;
    CLI_uint32_required("gpio_num", &pin);
    stat = gpio_pin_read_status((uint8_t)pin);
    CLI_printf("input            0x%x\n", (stat >> 12U) & 0x1U);
    CLI_printf("output           0x%x\n", (stat >>  8U) & 0x1U);
    CLI_printf("interrupt_enable 0x%x\n", (stat >> 16U) & 0x1U);
    CLI_printf("interrupt_type   0x%x\n", (stat >> 17U) & 0x7U);
    CLI_printf("gpio_mode        0x%x\n", (stat >> 24U) & 0x3U);
    CLI_printf("rdstat           0x%08x\n", stat);
}

static const struct cli_cmd_entry gpio_menu[] = {
    CLI_CMD_SIMPLE("set",    do_gpio_set,    "gpio_num -- drive pin high"),
    CLI_CMD_SIMPLE("clr",    do_gpio_clr,    "gpio_num -- drive pin low"),
    CLI_CMD_SIMPLE("toggle", do_gpio_toggle, "gpio_num -- toggle pin"),
    CLI_CMD_SIMPLE("mode",   do_gpio_mode,   "gpio_num mode (0=in,1=out) -- set direction"),
    CLI_CMD_SIMPLE("status", do_gpio_status, "gpio_num -- read pin status"),
    CLI_CMD_TERMINATE()
};

